import { Component, Inject, OnInit, ViewChild } from '@angular/core';
import { NgForm } from '@angular/forms';
import { NavigationExtras, Router } from '@angular/router';
import { finalize } from 'rxjs/operators';

import { AUTH_SERVICE_TOKEN, IAuthService } from 'app/authorization/auth.service';
import { NotificationService } from 'app/shared/services/notification.service';

@Component({
  selector: 'app-sign-in',
  templateUrl: './sign-in.component.html',
  styleUrls: ['./sign-in.component.scss']
})
export class SignInComponent implements OnInit {
  title = 'sign-in';
  agent = {
    account: '',
    password: ''
  };
  requesting = false;

  @ViewChild(NgForm) signInForm: NgForm;

  constructor(
    private router: Router,
    private notification: NotificationService,
    @Inject(AUTH_SERVICE_TOKEN) private authService: IAuthService
  ) {
    console.log('-> sign-in');
  }

  ngOnInit(): void {
    if (this.authService.isLoggedIn) {
      this.router.navigateByUrl(this.authService.redirectUrl);
    }
  }

  login(): void {
    if (this.signInForm && this.signInForm.valid) {
      const controls = this.signInForm.controls;

      for (const key in controls) {
        controls[key].disable();
      }
      this.requesting = true;
      this.notification.showLoading();
      this.authService.login(this.agent.account, this.agent.password)
        .pipe(
          finalize(() => {
            this.requesting = false;
            for (const key in controls) {
              controls[key].enable();
            }
            this.notification.hideLoading();
          })
        )
        .subscribe((data) => {
          if (data) {
            // Set our navigation extras object
            // that passes on our global query params and fragment
            const navigationExtras: NavigationExtras = {
              queryParamsHandling: 'preserve',
              preserveFragment: true
            };

            // Redirect the user
            this.router.navigateByUrl(this.authService.redirectUrl, navigationExtras);
          }
        });
    }
  }
}
